1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Scenario {
14	  customer: { yearsWithMHPCO: number };
15	  steps: QuoteStep[];
16	}
17	
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const COMPONENT_BASE = 25;
28	const BLOCK_SIZE = 3;
29	const BLOCK_BASE = 60;
30	
31	const FIRST_INSURANCE_RATE = 0.1;
32	const CURSE_RATE = 0.5;
33	const HIGH_ENCHANTMENT_RATE = 0.3;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	const PROCESSING_FEE = 5;
36	const ROUNDING_PRECISION = 6;
37	
38	const componentGroupBase = (count: number): number =>
39	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
40	
41	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
42	
43	const withSurcharge = (base: number, rate: number): number => base + base * rate;
44	
45	const isHighlyEnchanted = (item: Item): boolean =>
46	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
47	
48	const itemSurchargeRate = (item: Item): number =>
49	  FIRST_INSURANCE_RATE +
50	  (item.cursed ? CURSE_RATE : 0) +
51	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
52	
53	const mainItemPremium = (item: Item): number =>
54	  withSurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
55	
56	const mainItemTotal = (items: Item[]): number =>
57	  items
58	    .filter((item) => !isComponent(item))
59	    .reduce((sum, item) => sum + mainItemPremium(item), 0);
60	
61	const componentTotal = (items: Item[]): number => {
62	  const counts: Record<string, number> = {};
63	  for (const item of items.filter(isComponent)) {
64	    counts[item.type] = (counts[item.type] ?? 0) + 1;
65	  }
66	  const base = Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
67	  return withSurcharge(base, FIRST_INSURANCE_RATE);
68	};
69	
70	const roundUpToWhole = (amount: number): number =>
71	  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));
72	
73	const quotePremium = (items: Item[]): number =>
74	  roundUpToWhole(mainItemTotal(items) + componentTotal(items) + PROCESSING_FEE);
75	
76	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
77	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
78	  return { results };
79	};
